1	type Cell = [number, number]; // [x, y]
2	
3	function countLiveNeighbors(cells: Cell[], [x, y]: Cell): number {
4	  return cells.filter(
5	    ([nx, ny]) =>
6	      !(nx === x && ny === y) &&
7	      Math.abs(nx - x) <= 1 &&
8	      Math.abs(ny - y) <= 1,
9	  ).length;
10	}
11	
12	function survives(liveNeighbors: number): boolean {
13	  return liveNeighbors === 2 || liveNeighbors === 3;
14	}
15	
16	function isBornByReproduction(liveNeighbors: number): boolean {
17	  return liveNeighbors === 3;
18	}
19	
20	function isAlive(cells: Cell[], [x, y]: Cell): boolean {
21	  return cells.some(([cx, cy]) => cx === x && cy === y);
22	}
23	
24	const OFFSETS = [-1, 0, 1];
25	
26	function candidateCells(cells: Cell[]): Cell[] {
27	  const seen = new Map<string, Cell>();
28	  for (const [x, y] of cells) {
29	    for (const dx of OFFSETS) {
30	      for (const dy of OFFSETS) {
31	        const candidate: Cell = [x + dx, y + dy];
32	        seen.set(`${candidate[0]},${candidate[1]}`, candidate);
33	      }
34	    }
35	  }
36	  return [...seen.values()];
37	}
38	
39	/**
40	 * Computes the next generation of live cells from the current live cells,
41	 * applying Conway's rules.
42	 */
43	export function nextGeneration(cells: Cell[]): Cell[] {
44	  return candidateCells(cells).filter((cell) => {
45	    const liveNeighbors = countLiveNeighbors(cells, cell);
46	    return isAlive(cells, cell)
47	      ? survives(liveNeighbors)
48	      : isBornByReproduction(liveNeighbors);
49	  });
50	}
